/// <summary>
///
/// </summary>
public void postLoad()
{
    super();
    DataArea                     dataArea;
    ETGACFParameters             acfparameters = ETGACFParameters::find();
    DefaultDimensionView         DefaultDimensionView;
    DimAttributeOMBusinessUnit   dimAttributeOMBusinessUnit;
    GeneralJournalAccountEntry   generalJournalAccountEntry;
    GeneralJournalEntry          generalJournalEntry;
    AmountMST                    AmtUSD;

    this.Name = CustTable::find(this.AccountNum).name();
    this.CountryName = CustTable::find(this.AccountNum).countryName();
    this.Commidity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, acfparameters.MainCommodity);
    this.SubCommidity = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, acfparameters.SubCommodity);
    this.Vertical = ETGFixedAssetFinancialsDimensions::getDimensionDisplayValue(this.DefaultDimension, acfparameters.Vertical);


    select * from DefaultDimensionView where DefaultDimensionView.DEFAULTDIMENSION == this.DefaultDimension
         && DefaultDimensionView.Name == acfparameters.SubVertical;



    select * from dimAttributeOMBusinessUnit
        where dimAttributeOMBusinessUnit.value == DefaultDimensionView.DisplayValue;

    if (dimAttributeOMBusinessUnit)
    {
        this.SubVertical            = dimAttributeOMBusinessUnit.Name;
    }


    CustTrans custTransLocal = CustTrans::find(this.RecId);

    this.AmountoutstandinginLC = CustTrans::balanceMST(custTransLocal.AccountNum);//CustTrans::balanceReportingCurrency(custTransLocal.AccountNum);

    this.AmountUSD             = CustTrans::balanceUSD(custTransLocal);
    this.CurrencyLC            = Ledger::accountingCurrency();

    select firstonly Name from dataArea
    where dataArea.id       == this.DataAreaId;

    this.EntityName           = dataArea.name;

    CustTable custTable = CustTable::find(this.AccountNum);
    this.AmountoutstandinginTC = custTable.balancePerDate(this.TransDate);

    ExchangeRateUnionView ExchangeRateUnionView, ExchangeRateUnionViewLoc;

    select firstonly ExchangeRateUnionView order by ExchangeRateUnionView.ValidFrom desc
    where ExchangeRateUnionView.FromCurrencyCode == this.CurrencyCode && ExchangeRateUnionView.ToCurrencyCode == 'USD'
            && ExchangeRateUnionView.ValidFrom <= this.TransDate &&  ExchangeRateUnionView.ValidTo >= this.TransDate;

    if (this.CurrencyCode == 'USD')
    {
        this.ExchInUSD = 1;
    }
    else
    {
        this.ExchInUSD  = ( ExchangeRateUnionView.ExchangeRate) /100.00;
    }

    select firstonly  ExchangeRateUnionViewLoc order by ExchangeRateUnionViewLoc.ValidFrom desc
    where ExchangeRateUnionViewLoc.FromCurrencyCode == this.CurrencyCode && ExchangeRateUnionViewLoc.ToCurrencyCode == Ledger::accountingCurrency(CompanyInfo::current())
    && ExchangeRateUnionViewLoc.ValidFrom <= this.TransDate &&  ExchangeRateUnionViewLoc.ValidTo >=this.TransDate;

    if (this.CurrencyCode == Ledger::accountingCurrency(CompanyInfo::current() ))
    {
    this.ExchInLC   = 1;
    }
    else
    {
        this.ExchInLC = (ExchangeRateUnionViewLoc.ExchangeRate)/100.00;
    }


    select firstonly SubledgerVoucher, RecId from generalJournalEntry
        where generalJournalEntry.SubledgerVoucher == this.Voucher;

    select firstonly MainAccount from generalJournalAccountEntry
        where generalJournalAccountEntry.GeneralJournalEntry == generalJournalEntry.RecId
        && generalJournalAccountEntry.PostingType == LedgerPostingType::CustBalance;

    MainAccount mainAccount =  MainAccount::find(generalJournalAccountEntry.mainAccount);

    this.GLCode         = mainAccount.MainAccountId;
    this.GLDescription  = mainAccount.Name;

    this.GLCodeProstingProfile = DimensionAttributeValueCombination::find( CustLedgerAccounts::summaryLedgerDimension(this.AccountNum, this.PostingProfile)).DisplayValue;
    this.GLDescriptionPostingProfile = MainAccount::findByMainAccountId(this.GLCodeProstingProfile).Name;
    this.CustBalance =custTransLocal.remainAmountCur();






}
